# Start-Immich.ps1 - Dynamically generated by Install-Immich.ps1
Param(
    [string]$WSLUserName = 'ubuntu'
)

$ErrorActionPreference = 'Stop'

# Functionsファイルの読み込み
. $PSScriptRoot\Functions.ps1

function Write-StartLog {
    param(
        [string]$Message,
        [ValidateSet('INFO','WARN','ERROR')][string]$Level = 'INFO'
    )
    Write-Host "[Start-Immich] $Message"
}

Write-StartLog "Beginning Immich startup process..."

$AbsoluteImmichDirWSL = '/opt/immich'
Write-StartLog "Script started with Distro: '$script:Distro', ImmichDir: '$AbsoluteImmichDirWSL', User: '$WSLUserName'."

try {
    Write-StartLog "Ensuring WSL distro '$script:Distro' is running and initiating keep-alive..."
    wsl -d $script:Distro --exec dbus-launch true
    Write-StartLog "WSL distro '$script:Distro' keep-alive initiated."

    Start-Sleep -Seconds 5

    Write-StartLog "Attempting to start Immich services in '$AbsoluteImmichDirWSL' as user '$WSLUserName'..."
    $WslCommand = "cd '$AbsoluteImmichDirWSL' && docker compose pull && docker compose up -d"
    
    Write-StartLog "Executing in WSL: wsl -d $script:Distro -u $WSLUserName -- bash -c $WslCommand"
    wsl -d $script:Distro -u $WSLUserName -- bash -c "$WslCommand"
    Write-StartLog "Immich services startup command issued for '$script:Distro'."

} catch {
    Write-StartLog "An error occurred during Immich startup: $($_.Exception.Message) | StackTrace: $($_.ScriptStackTrace)" -Level ERROR
    exit 1
}

Write-StartLog "Start-Immich.ps1 finished successfully."
exit 0
